27: void fillMetadataContext(const std::vector<const MetadataProto*>& source_metadata,
28:                          const std::vector<std::string>& metadata_context_namespaces,
29:                          const std::vector<std::string>& typed_metadata_context_namespaces,
30:                          MetadataProto& metadata_context) {
31:   for (const auto& context_key : metadata_context_namespaces) {
32:     for (const MetadataProto* metadata : source_metadata) {
33:       if (metadata == nullptr) {
34:         continue;
35:       }
36:       const auto& filter_metadata = metadata->filter_metadata();
37:       if (const auto metadata_it = filter_metadata.find(context_key);
38:           metadata_it != filter_metadata.end()) {
39:         (*metadata_context.mutable_filter_metadata())[metadata_it->first] = metadata_it->second;
40:         break;
41:       }
42:     }
43:   }
44: 
45:   for (const auto& context_key : typed_metadata_context_namespaces) {
46:     for (const MetadataProto* metadata : source_metadata) {
47:       if (metadata == nullptr) {
48:         continue;
49:       }
50:       const auto& typed_filter_metadata = metadata->typed_filter_metadata();
51:       if (const auto metadata_it = typed_filter_metadata.find(context_key);
52:           metadata_it != typed_filter_metadata.end()) {
53:         (*metadata_context.mutable_typed_filter_metadata())[metadata_it->first] =
54:             metadata_it->second;
55:         break;
56:       }
57:     }
58:   }
59: }
