161: void FilterConfigPerRoute::merge(const FilterConfigPerRoute& other) {
162:   // We only merge context extensions here, and leave boolean flags untouched since those flags are
163:   // not used from the merged config.
164:   auto begin_it = other.context_extensions_.begin();
165:   auto end_it = other.context_extensions_.end();
166:   for (auto it = begin_it; it != end_it; ++it) {
167:     context_extensions_[it->first] = it->second;
168:   }
