171: void Filter::initiateCall(const Http::RequestHeaderMap& headers) {
172:   if (filter_return_ == FilterReturn::StopDecoding) {
173:     return;
174:   }
175: 
176:   auto&& maybe_merged_per_route_config =
177:       Http::Utility::getMergedPerFilterConfig<FilterConfigPerRoute>(
178:           decoder_callbacks_, [](FilterConfigPerRoute& cfg_base, const FilterConfigPerRoute& cfg) {
179:             cfg_base.merge(cfg);
180:           });
181: 
182:   Protobuf::Map<std::string, std::string> context_extensions;
183:   if (maybe_merged_per_route_config) {
184:     context_extensions = maybe_merged_per_route_config.value().takeContextExtensions();
185:   }
186: 
187:   // If metadata_context_namespaces or typed_metadata_context_namespaces is specified,
188:   // pass matching filter metadata to the ext_authz service.
189:   // If metadata key is set in both the connection and request metadata,
190:   // then the value will be the request metadata value.
191:   envoy::config::core::v3::Metadata metadata_context;
192:   fillMetadataContext({&decoder_callbacks_->streamInfo().dynamicMetadata(),
193:                        &decoder_callbacks_->connection()->streamInfo().dynamicMetadata()},
194:                       config_->metadataContextNamespaces(),
195:                       config_->typedMetadataContextNamespaces(), metadata_context);
196: 
197:   // Fill route_metadata_context from the selected route's metadata.
198:   envoy::config::core::v3::Metadata route_metadata_context;
199:   if (decoder_callbacks_->route() != nullptr) {
200:     fillMetadataContext({&decoder_callbacks_->route()->metadata()},
201:                         config_->routeMetadataContextNamespaces(),
202:                         config_->routeTypedMetadataContextNamespaces(), route_metadata_context);
203:   }
204: 
205:   Filters::Common::ExtAuthz::CheckRequestUtils::createHttpCheck(
206:       decoder_callbacks_, headers, std::move(context_extensions), std::move(metadata_context),
207:       std::move(route_metadata_context), check_request_, max_request_bytes_, config_->packAsBytes(),
208:       config_->headersAsBytes(), config_->includePeerCertificate(), config_->includeTLSSession(),
209:       config_->destinationLabels(), config_->allowedHeadersMatcher(),
210:       config_->disallowedHeadersMatcher());
211: 
212:   ENVOY_STREAM_LOG(trace, "ext_authz filter calling authorization server", *decoder_callbacks_);
213:   // Store start time of ext_authz filter call
214:   start_time_ = decoder_callbacks_->dispatcher().timeSource().monotonicTime();
215: 
216:   state_ = State::Calling;
217:   filter_return_ = FilterReturn::StopDecoding; // Don't let the filter chain continue as we are
218:                                                // going to invoke check call.
219:   cluster_ = decoder_callbacks_->clusterInfo();
220:   initiating_call_ = true;
221:   client_->check(*this, check_request_, decoder_callbacks_->activeSpan(),
222:                  decoder_callbacks_->streamInfo());
223:   initiating_call_ = false;
224: }
