317: Http::FilterHeadersStatus Filter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
318:   ENVOY_STREAM_LOG(trace,
319:                    "ext_authz filter has {} response header(s) to add and {} response header(s) to "
320:                    "set to the encoded response:",
321:                    *encoder_callbacks_, response_headers_to_add_.size(),
322:                    response_headers_to_set_.size());
323:   if (!response_headers_to_add_.empty()) {
324:     ENVOY_STREAM_LOG(
325:         trace, "ext_authz filter added header(s) to the encoded response:", *encoder_callbacks_);
326:     for (const auto& [key, value] : response_headers_to_add_) {
327:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
328:       headers.addCopy(key, value);
329:     }
330:   }
331: 
332:   if (!response_headers_to_set_.empty()) {
333:     ENVOY_STREAM_LOG(
334:         trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
335:     for (const auto& [key, value] : response_headers_to_set_) {
336:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
337:       headers.setCopy(key, value);
338:     }
339:   }
340: 
341:   if (!response_headers_to_add_if_absent_.empty()) {
342:     for (const auto& [key, value] : response_headers_to_add_if_absent_) {
343:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
344:       if (auto header_entry = headers.get(key); header_entry.empty()) {
345:         ENVOY_STREAM_LOG(trace, "ext_authz filter added header(s) to the encoded response:",
346:                          *encoder_callbacks_);
347:         headers.addCopy(key, value);
348:       }
349:     }
350:   }
351: 
352:   if (!response_headers_to_overwrite_if_exists_.empty()) {
353:     for (const auto& [key, value] : response_headers_to_overwrite_if_exists_) {
354:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key, value);
355:       if (auto header_entry = headers.get(key); !header_entry.empty()) {
356:         ENVOY_STREAM_LOG(
357:             trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
358:         headers.setCopy(key, value);
359:       }
360:     }
361:   }
362:   return Http::FilterHeadersStatus::Continue;
363: }
