403: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
404:   state_ = State::Complete;
405:   using Filters::Common::ExtAuthz::CheckStatus;
406:   Stats::StatName empty_stat_name;
407: 
408:   if (!response->dynamic_metadata.fields().empty()) {
409:     if (!config_->enableDynamicMetadataIngestion()) {
410:       ENVOY_STREAM_LOG(trace,
411:                        "Response is trying to inject dynamic metadata, but dynamic metadata "
412:                        "ingestion is disabled. Ignoring...",
413:                        *decoder_callbacks_);
414:       stats_.ignored_dynamic_metadata_.inc();
415:     } else {
416:       // Add duration of call to dynamic metadata if applicable
417:       if (start_time_.has_value() && response->status == CheckStatus::OK) {
418:         ProtobufWkt::Value ext_authz_duration_value;
419:         auto duration =
420:             decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
421:         ext_authz_duration_value.set_number_value(
422:             std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
423:         (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
424:             ext_authz_duration_value;
425:       }
426:       decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
427:                                                           response->dynamic_metadata);
428:     }
429:   }
430: 
431:   switch (response->status) {
432:   case CheckStatus::OK: {
433:     // Any changes to request headers or query parameters can affect how the request is going to be
434:     // routed. If we are changing the headers we also need to clear the route
435:     // cache.
436:     if (config_->clearRouteCache() &&
437:         (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
438:          !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
439:          !response->query_parameters_to_remove.empty())) {
440:       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
441:       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
442:     }
443: 
444:     ENVOY_STREAM_LOG(trace,
445:                      "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
446:     for (const auto& [key, value] : response->headers_to_set) {
447:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
448:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
449:       switch (check_result) {
450:       case CheckResult::OK:
451:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
452:         request_headers_->setCopy(Http::LowerCaseString(key), value);
453:         break;
454:       case CheckResult::IGNORE:
455:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
456:                          key, value);
457:         break;
458:       case CheckResult::FAIL:
459:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
460:                          key, value);
461:         rejectResponse();
462:         return;
463:       }
464:     }
465:     for (const auto& [key, value] : response->headers_to_add) {
466:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
467:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
468:       switch (check_result) {
469:       case CheckResult::OK:
470:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
471:         request_headers_->addCopy(Http::LowerCaseString(key), value);
472:         break;
473:       case CheckResult::IGNORE:
474:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
475:                          key, value);
476:         break;
477:       case CheckResult::FAIL:
478:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
479:                          key, value);
480:         rejectResponse();
481:         return;
482:       }
483:     }
484:     for (const auto& [key, value] : response->headers_to_append) {
485:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
486:           Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
487:       switch (check_result) {
488:       case CheckResult::OK: {
489:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
490:         Http::LowerCaseString lowercase_key(key);
491:         const auto header_to_modify = request_headers_->get(lowercase_key);
492:         // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
493:         // first (via `headers_to_add`). For example, given:
494:         // 1. Original headers {"original": "true"}
495:         // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
496:         // "2"}}
497:         //
498:         // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
499:         // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
500:         // "2"}}) to the request to upstream server by only sets `headers_to_append`.
501:         if (!header_to_modify.empty()) {
502:           ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
503:           // The current behavior of appending is by combining entries with the same key,
504:           // into one entry. The value of that combined entry is separated by ",".
505:           // TODO(dio): Consider to use addCopy instead.
506:           request_headers_->appendCopy(lowercase_key, value);
507:         }
508:         break;
509:       }
510:       case CheckResult::IGNORE:
511:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to append '{}':'{}'.", *decoder_callbacks_,
512:                          key, value);
513:         break;
514:       case CheckResult::FAIL:
515:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to append '{}':'{}'.",
516:                          *decoder_callbacks_, key, value);
517:         rejectResponse();
518:         return;
519:       }
520:     }
521: 
522:     ENVOY_STREAM_LOG(trace,
523:                      "ext_authz filter removed header(s) from the request:", *decoder_callbacks_);
524:     for (const auto& key : response->headers_to_remove) {
525:       // If the response contains an invalid header to remove, it's the same as trying to remove a
526:       // header that doesn't exist, so just ignore it.
527:       if (config_->validateMutations() && !Http::HeaderUtility::headerNameIsValid(key)) {
528:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
529:         continue;
530:       }
531:       // We don't allow removing any :-prefixed headers, nor Host, as removing them would make the
532:       // request malformed. checkDecoderHeaderMutation also performs this check, however, so only
533:       // perform this check explicitly if decoder header mutation rules is empty.
534:       if (!config_->hasDecoderHeaderMutationRules() &&
535:           !Http::HeaderUtility::isRemovableHeader(key)) {
536:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
537:         continue;
538:       }
539:       // Check header mutation is valid according to configured decoder header mutation rules.
540:       Http::LowerCaseString lowercase_key(key);
541:       switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
542:                                                   EMPTY_STRING)) {
543:       case CheckResult::OK:
544:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
545:         request_headers_->remove(lowercase_key);
546:         break;
547:       case CheckResult::IGNORE:
548:         ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
549:                          key);
550:         break;
551:       case CheckResult::FAIL:
552:         ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
553:                          key);
554:         rejectResponse();
555:         return;
556:       }
557:     }
558: 
559:     if (!response->response_headers_to_add.empty()) {
560:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
561:                        *decoder_callbacks_, response->response_headers_to_add.size());
562:       for (const auto& [key, value] : response->response_headers_to_add) {
563:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
564:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
565:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
566:                            value);
567:           rejectResponse();
568:           return;
569:         }
570:       }
571:       response_headers_to_add_ = Http::HeaderVector{response->response_headers_to_add.begin(),
572:                                                     response->response_headers_to_add.end()};
573:     }
574: 
575:     if (!response->response_headers_to_set.empty()) {
576:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
577:                        *decoder_callbacks_, response->response_headers_to_set.size());
578:       for (const auto& [key, value] : response->response_headers_to_set) {
579:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
580:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
581:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
582:                            value);
583:           rejectResponse();
584:           return;
585:         }
586:       }
587:       response_headers_to_set_ = Http::HeaderVector{response->response_headers_to_set.begin(),
588:                                                     response->response_headers_to_set.end()};
589:     }
590: 
591:     if (!response->response_headers_to_add_if_absent.empty()) {
592:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
593:                        *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
594:       for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
595:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
596:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
597:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
598:                            value);
599:           rejectResponse();
600:           return;
601:         }
602:       }
603:       response_headers_to_add_if_absent_ =
604:           Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
605:                              response->response_headers_to_add_if_absent.end()};
606:     }
607: 
608:     if (!response->response_headers_to_overwrite_if_exists.empty()) {
609:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
610:                        *decoder_callbacks_,
611:                        response->response_headers_to_overwrite_if_exists.size());
612:       for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
613:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
614:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
615:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
616:                            value);
617:           rejectResponse();
618:           return;
619:         }
620:       }
621:       response_headers_to_overwrite_if_exists_ =
622:           Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
623:                              response->response_headers_to_overwrite_if_exists.end()};
624:     }
625: 
626:     absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
627:     if (!response->query_parameters_to_set.empty()) {
628:       modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
629:           request_headers_->Path()->value().getStringView());
630:       ENVOY_STREAM_LOG(
631:           trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
632:       for (const auto& [key, value] : response->query_parameters_to_set) {
633:         if (config_->validateMutations() &&
634:             (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
635:              !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
636:           ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
637:                            key, value);
638:           rejectResponse();
639:           return;
640:         }
641:         ENVOY_STREAM_LOG(trace, "'{}={}'", *decoder_callbacks_, key, value);
642:         modified_query_parameters->overwrite(key, value);
643:       }
644:     }
645: 
646:     if (!response->query_parameters_to_remove.empty()) {
647:       if (!modified_query_parameters) {
648:         modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
649:             request_headers_->Path()->value().getStringView());
650:       }
651:       ENVOY_STREAM_LOG(trace, "ext_authz filter removed query parameter(s) from the request:",
652:                        *decoder_callbacks_);
653:       for (const auto& key : response->query_parameters_to_remove) {
654:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
655:         modified_query_parameters->remove(key);
656:       }
657:     }
658: 
659:     // We modified the query parameters in some way, so regenerate the `path` header and set it
660:     // here.
661:     if (modified_query_parameters) {
662:       const auto new_path =
663:           modified_query_parameters->replaceQueryString(request_headers_->Path()->value());
664:       ENVOY_STREAM_LOG(
665:           trace, "ext_authz filter modified query parameter(s), using new path for request: {}",
666:           *decoder_callbacks_, new_path);
667:       request_headers_->setPath(new_path);
668:     }
669: 
670:     if (cluster_) {
671:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
672:     }
673:     stats_.ok_.inc();
674:     continueDecoding();
675:     break;
676:   }
677: 
678:   case CheckStatus::Denied: {
679:     ENVOY_STREAM_LOG(trace, "ext_authz filter rejected the request. Response status code: '{}'",
680:                      *decoder_callbacks_, enumToInt(response->status_code));
681:     stats_.denied_.inc();
682: 
683:     if (cluster_) {
684:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_denied_);
685:       if (config_->chargeClusterResponseStats()) {
686:         Http::CodeStats::ResponseStatInfo info{config_->scope(),
687:                                                cluster_->statsScope(),
688:                                                empty_stat_name,
689:                                                enumToInt(response->status_code),
690:                                                true,
691:                                                empty_stat_name,
692:                                                empty_stat_name,
693:                                                empty_stat_name,
694:                                                empty_stat_name,
695:                                                empty_stat_name,
696:                                                false};
697:         config_->httpContext().codeStats().chargeResponseStat(info, false);
698:       }
699:     }
700: 
701:     // Check headers are valid.
702:     if (config_->validateMutations()) {
703:       for (const auto& [key, value] : response->headers_to_set) {
704:         if (!Http::HeaderUtility::headerNameIsValid(key) ||
705:             !Http::HeaderUtility::headerValueIsValid(value)) {
706:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
707:                            value);
708:           rejectResponse();
709:           return;
710:         }
711:       }
712:     }
713: 
714:     // setResponseFlag must be called before sendLocalReply
715:     decoder_callbacks_->streamInfo().setResponseFlag(
716:         StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
717:     decoder_callbacks_->sendLocalReply(
718:         response->status_code, response->body,
719:         [&headers = response->headers_to_set,
720:          &callbacks = *decoder_callbacks_](Http::HeaderMap& response_headers) -> void {
721:           ENVOY_STREAM_LOG(trace,
722:                            "ext_authz filter added header(s) to the local response:", callbacks);
723:           // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
724:           // override existing headers.
725:           for (const auto& [key, _] : headers) {
726:             response_headers.remove(Http::LowerCaseString(key));
727:           }
728:           // Then set all of the requested headers, allowing the same header to be set multiple
729:           // times, e.g. `Set-Cookie`.
730:           for (const auto& [key, value] : headers) {
731:             ENVOY_STREAM_LOG(trace, " '{}':'{}'", callbacks, key, value);
732:             response_headers.addCopy(Http::LowerCaseString(key), value);
733:           }
734:         },
735:         absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied);
736:     break;
737:   }
738: 
739:   case CheckStatus::Error: {
740:     if (cluster_) {
741:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_error_);
742:     }
743:     stats_.error_.inc();
744:     if (config_->failureModeAllow()) {
745:       ENVOY_STREAM_LOG(trace, "ext_authz filter allowed the request with error",
746:                        *decoder_callbacks_);
747:       stats_.failure_mode_allowed_.inc();
748:       if (cluster_) {
749:         config_->incCounter(cluster_->statsScope(), config_->ext_authz_failure_mode_allowed_);
750:       }
751:       if (config_->failureModeAllowHeaderAdd()) {
752:         request_headers_->addReferenceKey(
753:             Filters::Common::ExtAuthz::Headers::get().EnvoyAuthFailureModeAllowed, "true");
754:       }
755:       continueDecoding();
756:     } else {
757:       ENVOY_STREAM_LOG(
758:           trace, "ext_authz filter rejected the request with an error. Response status code: {}",
759:           *decoder_callbacks_, enumToInt(config_->statusOnError()));
760:       decoder_callbacks_->streamInfo().setResponseFlag(
761:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
762:       decoder_callbacks_->sendLocalReply(
763:           config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
764:           Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
765:     }
766:     break;
767:   }
768:   }
769: }
