771: void Filter::rejectResponse() {
772:   const Http::Code status = Http::Code::InternalServerError;
773:   ENVOY_STREAM_LOG(trace, "ext_authz filter invalidated the response. Response status code: {}",
774:                    *decoder_callbacks_, enumToInt(status));
775:   if (cluster_) {
776:     config_->incCounter(cluster_->statsScope(), config_->ext_authz_invalid_);
777:   }
778:   stats_.invalid_.inc();
779:   decoder_callbacks_->streamInfo().setResponseFlag(
780:       StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
781:   decoder_callbacks_->sendLocalReply(
782:       status, EMPTY_STRING, nullptr, absl::nullopt,
783:       Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzInvalid);
784: }
