786: bool Filter::isBufferFull(uint64_t num_bytes_processing) const {
787:   if (!allow_partial_message_) {
788:     return false;
789:   }
790: 
791:   uint64_t num_bytes_buffered = num_bytes_processing;
792:   const auto* buffer = decoder_callbacks_->decodingBuffer();
793:   if (buffer != nullptr) {
794:     num_bytes_buffered += buffer->length();
795:   }
796: 
797:   return num_bytes_buffered >= max_request_bytes_;
798: }
