800: void Filter::continueDecoding() {
801:   // After sending the check request, we don't need to buffer the data anymore.
802:   buffer_data_ = false;
803: 
804:   filter_return_ = FilterReturn::ContinueDecoding;
805:   if (!initiating_call_) {
806:     decoder_callbacks_->continueDecoding();
807:   }
808: }
