810: Filter::PerRouteFlags Filter::getPerRouteFlags(const Router::RouteConstSharedPtr& route) const {
811:   if (route == nullptr) {
812:     return PerRouteFlags{
813:         true /*skip_check_*/,
814:         envoy::extensions::filters::http::ext_authz::v3::CheckSettings() /*check_settings_*/};
815:   }
816: 
817:   const auto* specific_check_settings =
818:       Http::Utility::resolveMostSpecificPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_);
819:   if (specific_check_settings != nullptr) {
820:     return PerRouteFlags{specific_check_settings->disabled(),
821:                          specific_check_settings->checkSettings()};
822:   }
823: 
824:   return PerRouteFlags{
825:       false /*skip_check_*/,
826:       envoy::extensions::filters::http::ext_authz::v3::CheckSettings() /*check_settings_*/};
827: }
