23: Http::FilterFactoryCb ExtAuthzFilterConfig::createFilterFactoryFromProtoTyped(
24:     const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& proto_config,
25:     const std::string& stats_prefix, Server::Configuration::FactoryContext& context) {
26:   auto& server_context = context.serverFactoryContext();
27: 
28:   const auto filter_config =
29:       std::make_shared<FilterConfig>(proto_config, context.scope(), stats_prefix, server_context);
30:   // The callback is created in main thread and executed in worker thread, variables except factory
31:   // context must be captured by value into the callback.
32:   Http::FilterFactoryCb callback;
33: 
34:   if (proto_config.has_http_service()) {
35:     // Raw HTTP client.
36:     const uint32_t timeout_ms = PROTOBUF_GET_MS_OR_DEFAULT(proto_config.http_service().server_uri(),
37:                                                            timeout, DefaultTimeout);
38:     const auto client_config =
39:         std::make_shared<Extensions::Filters::Common::ExtAuthz::ClientConfig>(
40:             proto_config, timeout_ms, proto_config.http_service().path_prefix(), server_context);
41:     callback = [filter_config, client_config,
42:                 &server_context](Http::FilterChainFactoryCallbacks& callbacks) {
43:       auto client = std::make_unique<Extensions::Filters::Common::ExtAuthz::RawHttpClientImpl>(
44:           server_context.clusterManager(), client_config);
45:       callbacks.addStreamFilter(std::make_shared<Filter>(filter_config, std::move(client)));
46:     };
47:   } else {
48:     // gRPC client.
49:     const uint32_t timeout_ms =
50:         PROTOBUF_GET_MS_OR_DEFAULT(proto_config.grpc_service(), timeout, DefaultTimeout);
51: 
52:     THROW_IF_NOT_OK(Config::Utility::checkTransportVersion(proto_config));
53:     Envoy::Grpc::GrpcServiceConfigWithHashKey config_with_hash_key =
54:         Envoy::Grpc::GrpcServiceConfigWithHashKey(proto_config.grpc_service());
55:     callback = [&context, filter_config, timeout_ms,
56:                 config_with_hash_key](Http::FilterChainFactoryCallbacks& callbacks) {
57:       auto client_or_error =
58:           context.serverFactoryContext()
59:               .clusterManager()
60:               .grpcAsyncClientManager()
61:               .getOrCreateRawAsyncClientWithHashKey(config_with_hash_key, context.scope(), true);
62:       THROW_IF_STATUS_NOT_OK(client_or_error, throw);
63:       auto client = std::make_unique<Filters::Common::ExtAuthz::GrpcClientImpl>(
64:           client_or_error.value(), std::chrono::milliseconds(timeout_ms));
65:       callbacks.addStreamFilter(std::make_shared<Filter>(filter_config, std::move(client)));
66:     };
67:   }
68: 
69:   return callback;
70: }
